6: import * as vscode from 'vscode';
7: import * as fileSchemes from '../configuration/fileSchemes';
8: import * as languageModeIds from '../configuration/languageIds';
9: import * as typeConverters from '../typeConverters';
10: import { ClientCapability, ITypeScriptServiceClient } from '../typescriptService';
11: import { inMemoryResourcePrefix } from '../typescriptServiceClient';
12: import { coalesce } from '../utils/arrays';
13: import { Delayer, setImmediate } from '../utils/async';
14: import { nulToken } from '../utils/cancellation';
15: import { Disposable } from '../utils/dispose';
16: import { ResourceMap } from '../utils/resourceMap';
17: import { API } from './api';
18: import type * as Proto from './protocol/protocol';
