159: class SyncedBuffer {
160: 
161: 	private state = BufferState.Initial;
162: 
163: 	constructor(
164: 		private readonly document: vscode.TextDocument,
165: 		public readonly filepath: string,
166: 		private readonly client: ITypeScriptServiceClient,
167: 		private readonly synchronizer: BufferSynchronizer,
168: 	) { }
169: 
170: 	public open(): void {
171: 		const args: Proto.OpenRequestArgs = {
172: 			file: this.filepath,
173: 			fileContent: this.document.getText(),
174: 			projectRootPath: this.getProjectRootPath(this.document.uri),
175: 		};
176: 
177: 		const scriptKind = mode2ScriptKind(this.document.languageId);
178: 		if (scriptKind) {
179: 			args.scriptKindName = scriptKind;
180: 		}
181: 
182: 		const tsPluginsForDocument = this.client.pluginManager.plugins
183: 			.filter(x => x.languages.indexOf(this.document.languageId) >= 0);
184: 
185: 		if (tsPluginsForDocument.length) {
186: 			(args as any).plugins = tsPluginsForDocument.map(plugin => plugin.name);
187: 		}
188: 
189: 		this.synchronizer.open(this.resource, args);
190: 		this.state = BufferState.Open;
191: 	}
192: 
193: 	private getProjectRootPath(resource: vscode.Uri): string | undefined {
194: 		const workspaceRoot = this.client.getWorkspaceRootForResource(resource);
195: 		if (workspaceRoot) {
196: 			const tsRoot = this.client.toTsFilePath(workspaceRoot);
197: 			return tsRoot?.startsWith(inMemoryResourcePrefix) ? undefined : tsRoot;
198: 		}
199: 
200: 		return fileSchemes.isOfScheme(resource, fileSchemes.officeScript, fileSchemes.chatCodeBlock) ? '/' : undefined;
201: 	}
202: 
203: 	public get resource(): vscode.Uri {
204: 		return this.document.uri;
205: 	}
206: 
207: 	public get lineCount(): number {
208: 		return this.document.lineCount;
209: 	}
210: 
211: 	public get languageId(): string {
212: 		return this.document.languageId;
213: 	}
214: 
215: 	/**
216: 	 * @return Was the buffer open?
217: 	 */
218: 	public close(): boolean {
219: 		if (this.state !== BufferState.Open) {
220: 			this.state = BufferState.Closed;
221: 			return false;
222: 		}
223: 		this.state = BufferState.Closed;
224: 		return this.synchronizer.close(this.resource, this.filepath, mode2ScriptKind(this.document.languageId));
225: 	}
226: 
227: 	public onContentChanged(events: readonly vscode.TextDocumentContentChangeEvent[]): void {
228: 		if (this.state !== BufferState.Open) {
229: 			console.error(`Unexpected buffer state: ${this.state}`);
230: 		}
231: 
232: 		this.synchronizer.change(this.resource, this.filepath, events);
233: 	}
234: }
