    61→/**
    62→ * Manages synchronization of buffers with the TS server.
    63→ *
    64→ * If supported, batches together file changes. This allows the TS server to more efficiently process changes.
    65→ */
    66→class BufferSynchronizer {
    67→
    68→	private readonly _pending: ResourceMap<BufferOperation>;
    69→
    70→	constructor(
    71→		private readonly client: ITypeScriptServiceClient,
    72→		pathNormalizer: (path: vscode.Uri) => string | undefined,
    73→		onCaseInsensitiveFileSystem: boolean
