    87→	public close(resource: vscode.Uri, filepath: string, scriptKind: ScriptKind | undefined): boolean {
    88→		return this.updatePending(resource, new CloseOperation(filepath, scriptKind));
    89→	}
    90→
    91→	public change(resource: vscode.Uri, filepath: string, events: readonly vscode.TextDocumentContentChangeEvent[]) {
    92→		if (!events.length) {
    93→			return;
    94→		}
    95→
    96→		this.updatePending(resource, new ChangeOperation({
    97→			fileName: filepath,
    98→			textChanges: events.map((change): Proto.CodeEdit => ({
    99→				newText: change.text,
   100→				start: typeConverters.Position.toLocation(change.range.start),
   101→				end: typeConverters.Position.toLocation(change.range.end),
   102→			})).reverse(), // Send the edits end-of-document to start-of-document order
   103→		}));
   104→	}
   105→
   106→	public reset(): void {
   107→		this._pending.clear();
   108→	}
   109→
   110→	public beforeCommand(command: string): void {
   111→		if (command === 'updateOpen') {
   112→			return;
   113→		}
   114→
   115→		this.flush();
   116→	}
   117→
   118→	private flush() {
   119→		if (this._pending.size > 0) {
   120→			const closedFiles: string[] = [];
   121→			const openFiles: Proto.OpenRequestArgs[] = [];
   122→			const changedFiles: Proto.FileCodeEdits[] = [];
   123→			for (const change of this._pending.values()) {
   124→				switch (change.type) {
   125→					case BufferOperationType.Change: changedFiles.push(change.args); break;
   126→					case BufferOperationType.Open: openFiles.push(change.args); break;
   127→					case BufferOperationType.Close: closedFiles.push(change.args); break;
   128→				}
